          "itemListElement": [
            {
              "@type": "ListItem",
              "position": 1,
              "name": "Home",
              "item": "/"
            },
            {
              "@type": "ListItem",
              "position": 2,
              "name": "Professional Tax Return Filing - Process, Due Date & Slabs",
              "item": "/pt-returns"
            }
          ]
        },
        {
          "@type": "FAQPage",
          "mainEntity": [
            {
              "@type": "Question",
              "name": "What is a professional tax return and who must file it?",
              "acceptedAnswer": {
                "@type": "Answer",
                "text": "A periodic document filed with the state government declaring PT deducted from salaries (employers with PTRC) or PT paid on own income (self-employed with PTEC). Employers file Form III-B monthly or annually depending on liability. Self-employed typically make annual payment only. Mandatory in all 20 states that levy PT."
              }
            },
            {
              "@type": "Question",
              "name": "What is the difference between PTRC and PTEC?",
              "acceptedAnswer": {
                "@type": "Answer",
                "text": "PTRC is for employers who deduct PT from employee salaries - triggers periodic return filing obligation. PTEC is for self-employed professionals, business owners, partners, and directors who pay PT on their own income directly. Both must be obtained within 30 days of the triggering event."
              }
            },
            {
              "@type": "Question",
              "name": "What are the due dates for PT return filing?",
              "acceptedAnswer": {
                "@type": "Answer",
                "text": "Varies by state. Maharashtra: 15th of the following month (revised February 2026 notification). Karnataka: 20th. Telangana and AP: 10th. Tamil Nadu and Kerala: half-yearly. Gujarat: monthly or quarterly based on employee count. PTEC annual payment in Maharashtra: 30th June."
              }
            },
            {
              "@type": "Question",
              "name": "What is the penalty for late filing?",
              "acceptedAnswer": {
                "@type": "Answer",
                "text": "Maharashtra: Rs 1,000 per return within 1 month, Rs 2,000 beyond. Interest 1.25% per month + 10% penalty on unpaid tax. Late registration: Rs 5/day. Karnataka: 1.25% per month, max 50% of outstanding. These penalties compound monthly and can quickly exceed the tax itself."
              }
            },
            {
              "@type": "Question",
              "name": "Is professional tax deductible from income tax?",
              "acceptedAnswer": {
                "@type": "Answer",
                "text": "Yes. PT paid is deductible under Section 16 of the Income Tax Act from salary income. Available only under the old tax regime. Under the new default tax regime (AY 2024-25 onwards), Section 16 PT deduction is not available. PT is reflected in Form 16 issued by employer."
              }
            },
            {
              "@type": "Question",
              "name": "Which states do not levy professional tax?",
              "acceptedAnswer": {
                "@type": "Answer",
                "text": "Delhi, Uttar Pradesh, Rajasthan, Haryana, Punjab, Uttarakhand, Himachal Pradesh, Goa, Arunachal Pradesh, Jammu and Kashmir, Ladakh, and most Union Territories. Companies headquartered in these states but employing people in PT states must still register and comply in those states."
              }
            },
            {
              "@type": "Question",
              "name": "What is the maximum professional tax in India?",
              "acceptedAnswer": {
                "@type": "Answer",
                "text": "Rs 2,500 per person per year under Article 276(2) of the Constitution. Most states levy Rs 200/month with an extra Rs 100 in one month to reach Rs 2,500. For example, Maharashtra charges Rs 200/month for 11 months and Rs 300 in February, totalling Rs 2,500."
              }
            }
          ]
        }
      ]
    }
    </script>
